SourceCode.Declaration:
[DataContract]
public final class SalesInvoiceBusinessEventContract extends BusinessEventsContract
{
    private CustInvoiceId       invoiceId;
    private TransDate           transactionDate;
    private SalesId             salesId;
    private SalesAgreementId    salesAgreementNumber;
    private str                 dealNumber;
    private str                 source;
    private CustAccount         customerNo;
    private AmountCur           invoiceAmount;
    private CurrencyCode        currency;
    private RefRecId            recordId;
    private str                 transactionType;

    // Lines collection
    private List                lines;

}

Method.Source:
protected void initialize(CustInvoiceJour _journal)
{
    SalesTable              salesTable;
    SalesAgreementHeader    salesAgreementHeader;
    AgreementHeaderDefault  agreementHeaderDefault;

    // Hardcoded values
    transactionType = 'SalesInvoice';
    source          = 'D365';

    // Populate standard header fields from journal
    invoiceId       = _journal.InvoiceId;
    transactionDate = _journal.InvoiceDate;
    salesId         = _journal.SalesId;
    customerNo      = _journal.OrderAccount;
    currency        = _journal.CurrencyCode;
    recordId        = _journal.RecId;

    // Lookup SalesAgreement and Deal Number
    salesTable = SalesTable::find(_journal.SalesId);

    select firstonly salesAgreementHeader
        where salesAgreementHeader.RecId == salesTable.MatchingAgreement;

    if (salesAgreementHeader.RecId)
    {
        salesAgreementNumber = salesAgreementHeader.SalesNumberSequence;

        select firstonly agreementHeaderDefault
            where agreementHeaderDefault.AgreementHeader == salesAgreementHeader.RecId;

        if (agreementHeaderDefault.RecId)
        {
            dealNumber = agreementHeaderDefault.ETGDealNumber;
        }
    }

    // Initialize lines list
    lines = new List(Types::Class);

    // Populate lines and calculate total invoice amount
    this.populateLines(_journal);
}

private void populateLines(CustInvoiceJour _journal)
{
    CustInvoiceTrans invoiceTrans;

    invoiceAmount = 0;

    // Loop through lines for this specific invoice
    while select invoiceTrans
        where invoiceTrans.SalesId == _journal.SalesId
           && invoiceTrans.InvoiceId == _journal.InvoiceId
           && invoiceTrans.InvoiceDate == _journal.InvoiceDate
    {
        // Accumulate total header amount
        invoiceAmount += invoiceTrans.LineAmount;

        // Instantiate the line contract and pass down header values (like InvoiceId and Currency) + Line values
        SalesInvoiceLineBusinessEventContract lineContract = SalesInvoiceLineBusinessEventContract::construct(
            _journal.InvoiceId,
            invoiceTrans.Qty,
            invoiceTrans.LineAmount,
            invoiceTrans.ItemId,
            _journal.CurrencyCode,
            invoiceTrans.TaxGroup, // Used TaxGroup for TaxCode, can be changed to TaxItemGroup if preferred
            invoiceTrans.TaxAmount);

        lines.addEnd(lineContract);
    }
}

public static SalesInvoiceBusinessEventContract newFromCustInvoiceJour(CustInvoiceJour _journal)
{
    var contract = new SalesInvoiceBusinessEventContract();
    contract.initialize(_journal);
    return contract;
}

// --- Data Members for Collections ---

[DataMember('Lines'),
 DataCollectionAttribute(Types::Class, classStr(SalesInvoiceLineBusinessEventContract)),
 BusinessEventsDataMember('Invoice Lines')]
public List parmLines(List _lines = lines)
{
    lines = _lines;
    return lines;
}

